import json
with open('results/probing_results.json') as f:
    data = json.load(f)

# Per-category at each layer for French
print('FRENCH - Per-category MAE by layer:')
for layer in ['0', '8', '16', '24', '32']:
    cats = data['French'][layer]['per_category']
    print(f'  Layer {layer:>2}:')
    for cat in ['units', 'teens', 'decimal_tens', 'vigesimal_70s', 'vigesimal_80s', 'vigesimal_90s', 'hundreds']:
        if cat in cats:
            print(f'    {cat:>16}: {cats[cat][\"mean_mae\"]:7.2f}')

